+export function serializeRequestBody(
+  data: RequestData | undefined,
+  headers: Headers,
+): BodyInit | undefined {
+  if (data?.headers) {
+    for (const [key, value] of Object.entries(data.headers)) {
+      headers.set(key, value);
+    }
