+      cfg,
+      discordConfig,
+      useAccessGroups,
+      commandsAllowFromAccess,
+      guildInfo,
+      channelConfig,
+      memberRoleIds,
+      sender,
+      allowNameMatching,
+      ownerAllowListConfigured: ownerAllowList != null,
+      ownerAllowed: ownerOk,
+    });
+  }
+  return true;
